const express = require('express');
const app = express();
app.use(express.json());

app.post('/rappi/webhook', async (req, res) => {
  // Respond 200 immediately
  res.status(200).json({ received: true });

  const { event_type, order_id } = req.body;

  // Process asynchronously
  try {
    switch (event_type) {
      case 'order_created':
        await handleNewOrder(req.body);
        break;
      case 'courier_assigned':
        await handleCourierAssigned(req.body);
        break;
      case 'order_finished':
        await handleOrderFinished(req.body);
        break;
    }
  } catch (err) {
    console.error(`Error processing ${order_id}:`, err);
  }
});

async function handleNewOrder(payload) {
  if (await db.orderExists(payload.order_id)) return; // idempotency
  await db.saveOrder(payload);
  await erpClient.createOrder(payload);
  await notifyPickingTeam(payload.order_id);
}

